let a = 5; // グローバルスコープ

function first() {
  let b = 2; // first関数のスコープ

  function second() {
    let c = 3; // second関数のスコープ
    console.log(a + b + c); // 各スコープから変数を参照します。予想される出力: 10
  }

  second();
}

first();

function outer() {
  let a = 5;

  function inner() {
    console.log(a); // 外部スコープの変数aにアクセスします。予想される出力: 5
  }

  return inner;
}

let myInner = outer();
myInner();

var a = 5;
var a = 10; // 再宣言が可能です
console.log(a); // 予想される出力: 10

let b = 5;
// let b = 10; // 再宣言は不可能で、この行はエラーを引き起こします

const c = 5;
// const c = 10; // 再宣言は不可能で、この行はエラーを引き起こします

var a = 5;
let b = 10;
console.log(window.a); // varで宣言した変数はグローバルオブジェクトのプロパティとなります。予想される出力: 5
console.log(window.b); // letで宣言した変数はグローバルオブジェクトのプロパティとなりません。予想される出力: undefined

function varTest() {
  var x = 1;
  if (true) {
    var x = 2; // 同じスコープでの再宣言は可能
    console.log(x); // 予想される出力: 2
  }
  console.log(x); // 予想される出力: 2
}

function letTest() {
  let y = 1;
  if (true) {
    let y = 2;
    console.log(y); // 予想される出力: 2
  }
  console.log(y); // 予想される出力: 1
}

varTest();
letTest();

function greeting(name) {
  // テンプレートリテラルを使用
  var message = `Hello, ${name}!`;
  console.log(message);
}

greeting('John'); // 予想される出力: Hello, John!

// 変数の巻き上げにより、yはundefinedとなる
console.log(y); // 予想される出力: undefined
var y = 5;

// letやconstで宣言した変数は巻き上げられないため、この行はエラーとなる
// console.log(z); // 予想される出力: ReferenceError: z is not defined
let z = 5;

var x = 'global';

function outer() {
  var x = 'outer';

  function inner() {
    var x = 'inner';
    console.log(x); // 予想される出力: inner
  }

  inner();
  console.log(x); // 予想される出力: outer
}

outer();
console.log(x); // 予想される出力: global

