var x = 10; // 再宣言可能
console.log(x); // 予想される出力: 10

let y = 5;
// let y = 10; // 再宣言は不可能なため、この行はエラーとなる
y = 10; // ただし再代入は可能
console.log(y); // 予想される出力: 10

const z = 5;
