{
  let x = 'block scope';
  console.log(x); // block scopeが出力される
}
console.log(x); // ReferenceError: x is not defined

function example() {
  var x = 'function scope';
  console.log(x); // function scopeが出力される
}
example();
console.log(x); // ReferenceError: x is not defined

var globalVar = 'I am global!'; // グローバル変数

function example() {
  var localVar = 'I am local!'; // ローカル変数
  console.log(globalVar); // I am global!が出力される
  console.log(localVar); // I am local!が出力される
}

example();
console.log(globalVar); // I am global!が出力される
console.log(localVar); // ReferenceError: localVar is not defined

console.log(x); // undefinedが出力される
