let name = 'JavaScript';
let msg = `Hello, ${name}!`;
console.log(msg); // Hello, JavaScript!が出力される

{
  let blockScope = 'I am block scoped';
  var functionScope = 'I am function scoped';
  console.log(blockScope); // I am block scopedが出力される
  console.log(functionScope); // I am function scopedが出力される
}
console.log(blockScope); // ReferenceError: blockScope is not defined
